import React, { useState } from 'react';

export default function Notices() {
  const [notices, setNotices] = useState(
    JSON.parse(localStorage.getItem('notices')) || []
  );

  const [title, setTitle] = useState('');
  const [content, setContent] = useState('');

  const postNotice = () => {
    if (!title || !content) {
      alert('Fill in both fields.');
      return;
    }
    const newNotices = [{ title, content }, ...notices];
    setNotices(newNotices);
    localStorage.setItem('notices', JSON.stringify(newNotices));
    setTitle('');
    setContent('');
  };

  const deleteNotice = (index) => {
    const confirmDelete = window.confirm('Delete this notice?');
    if (confirmDelete) {
      const updated = notices.filter((_, i) => i !== index);
      setNotices(updated);
      localStorage.setItem('notices', JSON.stringify(updated));
    }
  };

  return (
    <div className="auth-container">
      <h2>Campus Notices</h2>
      <input
        placeholder="Notice Title"
        value={title}
        onChange={(e) => setTitle(e.target.value)}
      />
      <textarea
        placeholder="Notice Content"
        value={content}
        onChange={(e) => setContent(e.target.value)}
      />
      <button onClick={postNotice}>Post Notice</button>

      {notices.length === 0 ? (
        <p>No notices yet.</p>
      ) : (
        notices.map((n, i) => (
          <div key={i} style={{ marginTop: '10px', background: '#e9f5ff', padding: '10px', borderRadius: '5px' }}>
            <strong>{n.title}</strong>
            <p>{n.content}</p>
            <button onClick={() => deleteNotice(i)}>Delete</button>
          </div>
        ))
      )}
    </div>
  );
}
